import logging
import queue
import threading
from dataclasses import dataclass, field
from typing import Any, Callable, Dict, List, Optional

logger = logging.getLogger(__name__)


@dataclass
class Task:
    task_id: str
    fn: Callable[..., Any]
    args: tuple = ()
    kwargs: Dict[str, Any] = field(default_factory=dict)
    priority: int = 0


@dataclass
class TaskResult:
    task_id: str
    success: bool
    result: Any = None
    error: Optional[str] = None


class TaskDispatcher:
    def __init__(self, num_workers: int = 4):
        self._queue: queue.PriorityQueue[tuple] = queue.PriorityQueue()
        self._results: Dict[str, TaskResult] = {}
        self._workers: List[threading.Thread] = []
        self._shutdown = threading.Event()
        for i in range(num_workers):
            t = threading.Thread(target=self._worker_loop, name=f"worker-{i}", daemon=True)
            t.start()
            self._workers.append(t)

    def _worker_loop(self) -> None:
        while not self._shutdown.is_set():
            try:
                _, task = self._queue.get(timeout=1.0)
                try:
                    result = task.fn(*task.args, **task.kwargs)
                    self._results[task.task_id] = TaskResult(
                        task_id=task.task_id, success=True, result=result
                    )
                except Exception as exc:
                    self._results[task.task_id] = TaskResult(
                        task_id=task.task_id, success=False, error=str(exc)
                    )
            except queue.Empty:
                continue

    def dispatch(self, task: Task, ) -> None:
        self._queue.put((task.priority, task))
        logger.info("Dispatched task %s with priority %d", task.task_id, task.priority)

    def get_result(self, task_id: str) -> Optional[TaskResult]:
        return self._results.get(task_id)

    def shutdown(self) -> None:
        self._shutdown.set()
        for w in self._workers:
            w.join(timeout=5.0)
        logger.info("All workers shut down")

