from typing import Generic, List, Optional, TypeVar

T = TypeVar("T")


class CircularBuffer(Generic[T]):
    """Fixed-size circular buffer with overwrite-on-full semantics."""

    def __init__(self, capacity: int):
        if capacity <= 0:
            raise ValueError("Capacity must be positive")
        self._capacity = capacity
        self._buffer: List[Optional[T]] = [None] * capacity
        self._write_idx = 0
        self._count = 0

    def write(self, item: T) -> None:
        self._buffer[self._write_idx] = item
        self._write_idx = (self._write_idx + 1) % self._capacity
        if self._count < self._capacity:
            self._count += 1

    def read_last(self, n: int) -> List[T]:
        """Return the last n items written, oldest first."""
        if n <= 0:
            return []
        n = min(n, self._count)
        result: List[T] = []
        start = (self._write_idx - n) % self._capacity
        for i in range(n):
            idx = (start + i) % self._capacity
            item = self._buffer[idx]
            if item is not None:
                result.append(item)
        return result

    @property
    def count(self) -> int:
        return self._count

    @property
    def capacity(self) -> int:
        return self._capacity

    @property
    def is_full(self) -> bool:
        return self._count

