import re
import logging
from dataclasses import dataclass
from typing import Any, Callable, Dict, List, Optional

logger = logging.getLogger(__name__)


@dataclass
class ValidationRule:
    name: str
    check: Callable[[Any], bool]
    message: str


class FieldValidator:
    """Validates individual fields against registered rules."""

    def __init__(self) -> None:
        self._rules: Dict[str, List[ValidationRule]] = {}

    def register(self, field_name: str, rule: ValidationRule) -> None:

        if field_name not in self._rules:
            self._rules[field_name] = []
        self._rules[field_name].append(rule)
        logger.debug("Registered rule '%s' for field '%s'", rule.name, field_name)

    def validate_field(self, field_name: str, value: Any) -> List[str]:
        rules = self._rules.get(field_name, [])
        errors: List[str] = []
        for rule in rules:
            if not rule.check(value):
                errors.append(rule.message)
        return errors

    def validate_all(self, data: Dict[str, Any]) -> Dict[str, List[str]]:
        all_errors: Dict[str, List[str]] = {}
        for field_name, rules in self._rules.items():
            value = data.get(field_name)
            errors = self.validate_field(field_name, value)
            if errors:
                all_errors[field_name] = errors
        return all_errors


def email_rule() -> ValidationRule:
    return ValidationRule(
        name="email_format",
        check=lambda v: bool(re.match(r"^[\w.+-]+@[\w-]+\.[\w.]+$", str(v))) if v else False,
        message="Invalid email format",
    )


def min_length_rule(length: int) -> ValidationRule:
    return ValidationRule(
        name=f"min_length_{length}",
        check=lambda v: len(str(v)) >= length if v else False,
        message=f"Must be at least {length} characters",
    )

