import logging
import random
from dataclasses import dataclass
from typing import Optional, Set, Type

logger = logging.getLogger(__name__)


@dataclass
class RetryConfig:
    max_retries: int = 3
    base_delay: float = 1.0
    max_delay: float = 60.0
    jitter: bool = True
    retryable_exceptions: Set[Type[Exception]] = None  # type: ignore[assignment]

    def __post_init__(self) -> None:
        if self.retryable_exceptions is None:
            self.retryable_exceptions = {Exception}


class RetryPolicy:
    def __init__(self, config: Optional[RetryConfig] = None):
        self._config = config or RetryConfig()
        self._attempt = 0

    def record_attempt(self) -> None:
        self._attempt += 1

    @property
    def attempts(self) -> int:
        return self._attempt

    def should_retry(self, exc: Exception) -> bool:
        if self._attempt >= self._config.max_retries:
            return False
        return isinstance(exc, tuple(self._config.retryable_exceptions))

    def get_delay(self) -> float:
        delay = min(
            self._config.base_delay * (2 ** self._attempt),
            self._config.max_delay,
        )
        if self._config.jitter:
            delay *= random.uniform(0.5, 1.5)
        return delay
